// Parsear respuesta GLM Z1 y combinar con stats
const stats = $('SplitInBatches — Por Artista').item.json;
const glmResponse = $input.first().json;
const analisis = glmResponse.choices?.[0]?.message?.content || 'Análisis no disponible esta semana.';

// Calcular tendencia
const tendencia = stats.fans_nuevos_semana > 0
  ? `📈 +${stats.fans_nuevos_semana} fans nuevos esta semana`
  : '📊 Sin fans nuevos esta semana — momento de activar promoción';

const reporte = `📊 *Reporte Semanal — ${stats.nombre_artistico}*\n_Lunes ${new Date().toLocaleDateString('es-MX')}_\n\n` +
  `*📈 Tu semana en números:*\n` +
  `• ${tendencia}\n` +
  `• 👥 Fans totales: ${stats.fans_total}\n` +
  `• 🎟️ Eventos próximos (30 días): ${stats.eventos_proximos}\n` +
  `• 📋 Nuevas contrataciones: ${stats.contrataciones_semana}\n` +
  `• 💎 Puntos acumulados fans: ${stats.puntos_total_fans}\n\n` +
  `*🤖 Análisis MYSTIC:*\n${analisis}\n\n` +
  `_Ver reporte completo: https://sonoradigitalcorp.com/dashboard_`;

return [{ json: { reporte, telegram_chat_id: stats.telegram_chat_id } }];
